// src/components/Dashboard.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Drawer, List, ListItem, ListItemText, ListItemIcon, Box, Typography, IconButton, Divider } from '@mui/material';
import { AccountCircle, Dashboard as DashboardIcon, Work as WorkIcon } from '@mui/icons-material';

function Dashboard() {
  const [role, setRole] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const storedRole = localStorage.getItem('role');
    if (!storedRole) {
      navigate('/login');
    } else {
      setRole(storedRole);
    }
  }, [navigate]);

  const toggleDrawer = (open) => () => {
    setDrawerOpen(open);
  };

  const navigateTo = (path) => {
    navigate(path);
    setDrawerOpen(false); // Close the drawer after navigation
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <Drawer
        sx={{
          width: 240,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: 240,
            boxSizing: 'border-box',
          },
        }}
        variant="persistent"
        anchor="left"
        open={drawerOpen}
      >
        <List>
          <ListItem button onClick={toggleDrawer(false)}>
            <ListItemText primary="Close" />
          </ListItem>
          <Divider />
          <ListItem button onClick={() => navigateTo('/profile')}>
            <ListItemIcon><AccountCircle /></ListItemIcon>
            <ListItemText primary="Profile" />
          </ListItem>

          {/* Manager-specific items */}
          {role === 'Manager' && (
            <>
              <ListItem button onClick={() => navigateTo('/employee-dashboard')}>
                <ListItemIcon><DashboardIcon /></ListItemIcon>
                <ListItemText primary="Employee" />
              </ListItem>
              <ListItem button onClick={() => navigateTo('/company-dashboard')}>
                <ListItemIcon><DashboardIcon /></ListItemIcon>
                <ListItemText primary="Company" />
              </ListItem>
              <ListItem button onClick={() => navigateTo('/records-dashboard')}>
                <ListItemIcon><WorkIcon /></ListItemIcon>
                <ListItemText primary="Records" />
              </ListItem>
            </>
          )}

          {/* Employee-specific items */}
          {role === 'Employee' && (
            <>
              <ListItem button onClick={() => navigateTo('/work-entry')}>
                <ListItemIcon><WorkIcon /></ListItemIcon>
                <ListItemText primary="Work Entry" />
              </ListItem>
              <ListItem button onClick={() => navigateTo('/work-details')}>
                <ListItemIcon><WorkIcon /></ListItemIcon>
                <ListItemText primary="Work Details" />
              </ListItem>
              <ListItem button onClick={() => navigateTo('/create-company')}>
                <ListItemIcon><WorkIcon /></ListItemIcon>
                <ListItemText primary="Create Company" />
              </ListItem>
            </>
          )}
        </List>
      </Drawer>

      {/* Main Content Area */}
      <Box
        component="main"
        sx={{
          flexGrow: 1,
          bgcolor: 'background.default',
          p: 3,
        }}
      >
        <Typography variant="h4" align="center" gutterBottom>
          Dashboard
        </Typography>
        {role === 'Manager' && (
          <Box>
            <Typography variant="h5" align="center" gutterBottom>
              Manager Dashboard
            </Typography>
            {/* Additional manager content here */}
          </Box>
        )}

        {role === 'Employee' && (
          <Box>
            <Typography variant="h5" align="center" gutterBottom>
              Employee Dashboard
            </Typography>
            {/* Additional employee content here */}
          </Box>
        )}
      </Box>
    </Box>
  );
}

export default Dashboard;
